п»ҝINSERT INTO public.photos VALUES (25025, 'Casa sin Duende 1976', 'El inmueble esquinero entre Gascв”ңв”Ӯn de Gotor y Juan Pablo Bonet desde los aв”ңв–’os 30 del pasado siglo era denominado "La Casa del Duende", por un episodio de moderada histeria colectiva basado en el engaв”ңв–’o, la supersticiв”ңв”Ӯn y el sensacionalismo de los medios de comunicaciв”ңв”Ӯn de masas. Por la fuerza de la costumbre, que es nuestra guв”ңВЎa y lumbre, el edificio de nueva planta que lo ha sustituido es denominado "Edificio Duende", para que la realidad no acabe distorsionando las improbables fantasв”ңВЎas. En la imagen, los andamios seв”ңв–’alan el inminente derribo. En los bajos, pintadas con algunas de las reivindicaciones del momento: libertad de los presos polв”ңВЎticos, no a los yanquis, no a las bases. A la izquierda, los controvertidos laboratorios ULTA y su fachada a la calle Gascв”ңв”Ӯn de Gotor. Fuente visual: Gerardo Sancho Ramo en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19709494442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19709494442.webp', 'https://www.flickr.com/photos/zaragozaantigua/19709494442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
