INSERT INTO public.photos VALUES (25026, 'Av. de la Repв”ңв•‘blica 1935', 'Imagen en altura del solar previsto para la construcciв”ңв”Ӯn de la "Casa Social", o edificio de servicios varios de la Confederaciв”ңв”Ӯn Hidrogrв”ңГӯfica del Ebro en la avenida de la Repв”ңв•‘blica. Dentro del solar, dos casas que luego serв”ңВЎan derribadas. A la izquierda, vista parcial de la "Casa del Ebro" o casa-oficina central de la Confederaciв”ңв”Ӯn Sindical Hidrogrв”ңГӯfica del Ebro (CSHE) construida a finales de los aв”ңв–’os veinte con proyecto del arquitecto Pascual Bravo Sanfeliu. Entre este edificio y el solar de la imagen, vista de la nueva calle de servicio abierta entre el paseo de Sagasta y la calle Gil de Jasa desde la que se accedв”ңВЎa a la casa-oficina de la entidad hidrogrв”ңГӯfica. Tras el solar, la calle Gil de Jasa, y al fondo, insв”ңв”Ӯlita visiв”ңв”Ӯn directa del edificio de las Clв”ңВЎnicas Universitarias, y de la Facultad de Medicina. A la derecha, la calle Mariano Lagasca, con la clв”ңВЎnica del Doctor Lozano. El inicio de las obras de este nuevo edificio, con proyecto de los hermanos Borobio, estaba previsto desde 1934, aunque no comenzaron hasta finales de 1936, para terminarse una dв”ңВ®cada despuв”ңВ®s (diciembre de 1946). Fuente visual: foto Marв”ңВЎn Chivite, en "La Crв”ңв”Ӯnica" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64452000, -0.88630900, '0101000020E61000009AD024B1A45CECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21884362772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21884362772.webp', 'https://www.flickr.com/photos/zaragozaantigua/21884362772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25194, 'Ciudad Universitaria 1935', 'Planta de emplazamiento de la Facultad de Filosofв”ңВЎa y Letras en la Ciudad Universitaria. Regino Borobio y Josв”ңВ® Beltrв”ңГӯn, Zaragoza, 1935. Plano del proyecto de Ciudad Universitaria en el que se remarca el lugar donde serв”ңГӯ levantada la Facultad de Filosofв”ңВЎa y Letras en 1940. La iniciativa de construir un campus junto a la plaza de Espaв”ңв–’a (hoy San Francisco) proviene de 1933. El recinto fue de uso militar entre 1936 y 1939. La Facultad de Derecho se levantв”ңв”Ӯ en 1945 y la de Ciencias en 1950. Fuente: www.facebook.com/photo.php?fbid=1496903440626884&set=...', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64187100, -0.89815500, '0101000020E6100000E8A4F78DAFBDECBF1BA034D428D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21973612358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21973612358.webp', 'https://www.flickr.com/photos/zaragozaantigua/21973612358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25027, 'P.в”¬в•‘ del General Mola 1976', 'Aspecto del ascendente paseo del General Mola en donde finaliza, desde la izquierda, el camino de las Torres, y desde donde arranca Juan Pablo Bonet, hacia la derecha. Salvo algunos pequeв”ңв–’os detalles, su imagen es el resultado de la mutaciв”ңв”Ӯn que este paseo habв”ңВЎa padecido en la segunda mitad del siglo. A la izquierda, в”ңв•‘ltimos momentos del hotelito diseв”ңв–’ado por Pascual Bravo en el antiguo nв”¬в•‘ 33. A la derecha, continuaban las obras en el controversial bloque de Colmenero, uno de los varios pufos de este destacado emprendedor. La conversiв”ңв”Ӯn del andador central del paseo en aparcamiento gratis para privados vehв”ңВЎculos a motor de explosiв”ңв”Ӯn, resultado del colapso de un sistema que inundв”ңв”Ӯ con decenas de miles de estas unidades una trama viaria que nunca podrв”ңВЎa absorber en superficie el problema de la geomв”ңВ®trica explosiв”ңв”Ӯn y ocupaciв”ңв”Ӯn del espacio pв”ңв•‘blico que el desarrollismo, el mercado, y los intereses privados, habв”ңВЎan creado. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23714237259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23714237259.webp', 'https://www.flickr.com/photos/zaragozaantigua/23714237259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25030, 'Juan Pablo Bonet 1977', 'Imagen con la fachada de los Laboratorios ULTA decorada con pintadas alusivas a las movilizaciones protagonizadas por sus trabajadores en la primavera de ese aв”ңв–’o. Una de ellas dice "Toda la plantilla de ULTA despedida por el capricho de un hombre (Fernando Cuenca Villoro, propietario) que cree puede jugar con 110 familias". Otra pintada, del PCE, reivindicaba la abstenciв”ңв”Ӯn en el referв”ңВ®ndum sobre el Proyecto de Ley para la Reforma Polв”ңВЎtica celebrado el 15 de diciembre del aв”ңв–’o anterior, donde se pedв”ңВЎa ratificar la Ley para la Reforma Polв”ңВЎtica (incluyendo la de las Cortes), que ya habв”ңВЎa sido aprobada previamente en las Cortes franquistas. Esta fue la traducciв”ңв”Ӯn efectiva del archipublicitado y melв”ңв”Ӯdico "jingle" (sonsonete) del "Habla, pueblo, habla". Aparcado en la calzada, un R-6. Fuente visual: Archivo Histв”ңв”Ӯrico CCOO Aragв”ңв”Ӯn-AHCCOOAR.FFT.1977/001.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30904961722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30904961722.webp', 'https://www.flickr.com/photos/zaragozaantigua/30904961722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25040, 'Calle de Cervantes 1940', '"Farmв”ңГЎcia de l''empresa farmacв”ңВҝutica Laboratorios Verkos". Imagen capturada en el interior de la farmacia que Laboratorios Verkos habв”ңВЎa habilitado en los bajos del novв”ңВЎsimo edificio proyectado por el arquitecto Teodoro Rв”ңВЎos Balaguer en moderno estilo racionalista como sede de estos laboratorios farmacв”ңВ®uticos. Mientras que el ingreso a los laboratorios se realizaba desde la calle de Gil de Jasa, el de este despacho de farmacia estaba en la calle de Cervantes (al fondo de la imagen). Asв”ңВЎ fue hasta mediados de la dв”ңВ®cada de los aв”ңв–’os setenta. De vecino inmediato tenв”ңВЎa al Colegio Alemв”ңГӯn y la Jefatura Provincial del "Ortsgruppe" (Grupo Local) del NSDAP (por las siglas en alemв”ңГӯn del Partido Nacionalsocialista Obrero Alemв”ңГӯn) en Zaragoza. Fuente visual: foto Gabriel Casas i Galobardes para Laboratorios Verkos, en Arxiu Nacional de Catalunya.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42337836452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42337836452.webp', 'https://www.flickr.com/photos/zaragozaantigua/42337836452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25050, 'P.в”¬в•‘ de Sagasta 1907', 'Imagen de la casa del nв”¬в•‘ 20 duplicado del paseo de Sagasta capturada desde la zona central del paseo, por la que todavв”ңВЎa circulaban los coches de la lв”ңВЎnea Torrero del tranvв”ңВЎa. Esta era la imponente vivienda diseв”ңв–’ada en 1903 por el arquitecto Luis de la Figuera y Lezcano para Nicolв”ңГӯs Escoriaza y Fabro, patriarca de esta poderosa y referencial familia local. Ademв”ңГӯs, aquв”ңВЎ estuvo temporalmente radicado el consulado de Bв”ңВ®lgica. En el centro de la imagen y en la terraza del primer piso posa la familia de Nicolв”ңГӯs Escoriaza. A la derecha queda el ingreso a la calle de Miguel de Cervantes. Este inmueble fue derribado en la segunda mitad de los convulsos aв”ңв–’os setenta del pasado siglo, y junto con los solares de las siguientes propiedades sirviв”ңв”Ӯ de base sobre la que finalmente fue construida una tremenda mole moderna de nueve alturas que desde entonces impera en el lugar.', 1907, 1907, 1907, 'Anos 1900', 'UNIVERSIDAD', 41.64385400, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF0BB3D0CE69D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51803780153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51803780153.webp', 'https://www.flickr.com/photos/zaragozaantigua/51803780153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25051, 'Calle la Paz 1935', 'El 8 de junio de 1934, el doctor Roncalв”ңВ®s pidiв”ңв”Ӯ autorizaciв”ңв”Ӯn al Ayuntamiento para la reforma de su clв”ңВЎnica, sita en la calle de la Paz nв”ңв•‘mero 5. El proyecto, firmado por Teodoro Rв”ңВЎos, resultв”ңв”Ӯ ser de nueva construcciв”ңв”Ӯn. El establecimiento resultante fue denominado Clв”ңВЎnica de San Ignacio, y fueron sus dueв”ңв–’os los doctores Roncalв”ңВ®s, Val-Carreres Gotor y Julio Ariв”ңв–’o. La clв”ңВЎnica contaba con dos pisos, en los que habв”ңВЎa 20 habitaciones de las que faltaba el nв”ңв•‘mero 13, debido a la presencia habitual allв”ңВЎ de profesionales taurinos. Las enfermeras eran hermanas de Santa Ana. La clв”ңВЎnica se cerrв”ңв”Ӯ en 1989 y el edificio fue derribado.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64263100, -0.88532200, '0101000020E6100000EDBC8DCD8E54ECBFA9328CBB41D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51982322459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51982322459.webp', 'https://www.flickr.com/photos/zaragozaantigua/51982322459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25053, 'P.в”¬в•‘ del General Mola 1977', 'Imagen capturada en el paseo del General Mola cuando por в”ңВ®l transitaba el cortejo organizado por la Asociaciв”ңв”Ӯn de Vecinos de Venecia que escenificaba el в”¬ВҪentierroв”¬в•— de las hasta entonces "fiestas carcas, oficiales, religiosasГ”ГҮВӘetc.", que desde este sureв”ңв–’o barrio llegarв”ңВЎa hasta la Lonja, tradicional edificio donde las tradicionalistas autoridades y "gente de orden" celebraban sus particulares fiestas del Pilar, mientras que al pueblo comв”ңв•‘n se le dejaba la tarea de aplaudir y vitorear... pero desde fuera del recinto. En la imagen, la comitiva camina por el bulevar central del paseo a la altura, a la derecha, del mastodв”ңв”Ӯntico nuevo gran inmueble en construcciв”ңв”Ӯn de los nв”ңв•‘meros 32-38 del paseo, resultado de la destrucciв”ңв”Ӯn previa de todos los "hotelitos" que allв”ңВЎ se encontraban desde principios de siglo. Abre la marcha un carrito de bebв”ңВ® con un cartel que reza "Nucleares, no", mientras tras в”ңВ®l varias personas portan el ataud que representaba a las viejas fiestas, repleto para la ocasiв”ңв”Ӯn de bebidas espirituosas con que "aguantar con buen humor el largo funeral". Ese aв”ңв–’o fue в”ңВ®l в”ңв•‘ltimo en que la "Zaragoza de bien" organizв”ңв”Ӯ el espectв”ңГӯculo de la "Reina de las Fiestas" celebrado en la Lonja, que en esta postrera ediciв”ңв”Ӯn recayв”ңв”Ӯ (como era tradicional, de forma digital) en Marв”ңВЎa Cristina Ruiz Santos.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64350100, -0.88613700, '0101000020E610000052D158FB3B5BECBFBEF8A23D5ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54845967602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54845967602.webp', 'https://www.flickr.com/photos/zaragozaantigua/54845967602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25100, 'Casa de la Paz 1992', 'Imagen capturada en las traseras de la "Casa de la Paz" habilitada en el abandonado hotelito del nв”¬в•‘ 52 del paseo de Sagasta como semillero de insumisos al Servicio Militar Obligatorio. Al fondo, la medianera del "Edificio Rosales" en el nв”¬в•‘ 50 del paseo, inmueble donde estaba radicada la emisora de radio controlada por la Conferencia Episcopal Espaв”ңв–’ola. Una pintada alusiva al preso ejeano Antonio Oriol pone en antecedentes el posado, en primer tв”ңВ®rmino, de una irrepetible galerв”ңВЎa de insumisos representativa de la notable diversidad polв”ңВЎtica de la в”ңВ®poca que caracterizaba este amplio movimiento social, uno de los mв”ңГӯs importantes en el principio de la dв”ңВ®cada.', 1992, 1992, 1992, 'Anos 90', 'UNIVERSIDAD', 41.64183400, -0.88693100, '0101000020E6100000DBDFD91EBD61ECBFFEBAD39D27D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201821227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201821227.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201821227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25430, 'P.в”¬в•‘ de Sagasta 1911', 'Vista del puente sobre la zanja del ferrocarril de la compaв”ңв–’в”ңВЎa MZA, en el punto de cruce entre el paseo de Sagasta ( por arriba, de derecha a izquierda), y la trinchera, abajo, de la vв”ңВЎa del ferrocarril de los directos Madrid-Barcelona. Esta vв”ңВЎa viene desde el fondo, donde estв”ңГӯ la estaciв”ңв”Ӯn de Campo Sepulcro, y va en direcciв”ңв”Ӯn a la estaciв”ңв”Ӯn de Miraflores. Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'UNIVERSIDAD', 41.64222500, -0.88608400, '0101000020E61000009D4830D5CC5AECBF39D6C56D34D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20972383200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20972383200.webp', 'https://www.flickr.com/photos/zaragozaantigua/20972383200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25593, 'Depв”ңв”Ӯsitos de Pignatelli 1965', 'Mв”ңГұs que interesante vista en altura centrada en los veteranos depв”ңв”Ӯsitos de Pignatelli, junto al homв”ңв”Ӯnimo parque. En primer tв”ңВ®rmino, el paseo de Cuв”ңВ®llar y la vв”ңВЎa de San Fernando, que confronta las escuelas de la Milagrosa con el cuartel de Castillejos. La calle del Maestro Estremiana, hacia la izquierda, conduce al paseo de Ruiseв”ңв–’ores, tras el que destaca el moderno Grupo Salduba. En la margen izquierda del rв”ңВЎo Huerva, despejado entorno ante el Hogar Sierra de Alcubierre, y vista parcial a la derecha de la antigua fв”ңГӯbrica textil de Cв”ңГӯndido Castillo. Las instalaciones de la Editorial Luis Vives S.A., junto a la calle homв”ңв”Ӯnima, dan paso a las ordenadas Casas Baratas de Miralbueno y la gran estructura del colegio de La Salle. Finalmente y al fondo, el paseo de Fernando el Catв”ңв”Ӯlico y la plaza de San Francisco.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63621300, -0.88713500, '0101000020E6100000FA6184F06863ECBF2025766D6FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50359769397.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50359769397.webp', 'https://www.flickr.com/photos/zaragozaantigua/50359769397/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25737, 'Camino de las Torres 1951', 'Desde Juan Pablo Bonet, imagen del в”ңв•‘ltimo tramo del camino de las Torres, al fondo, y del cruce del paseo del General Mola. A la derecha, la manzana que ocupaba la TUDOR, expectante de nuevas edificaciones residenciales. A la izquierda, Casa Faci. Hay un carro, a la derecha, maniobrando temerariamente, y peatones cruzando por doquiera, pero a nadie parece importarle: aв”ңв•‘n no ha llegado la Era de los Automв”ңв”Ӯviles. Fuente visual: Archivo Pв”ңв•‘blico Municipal, Archivo Mora.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20313336656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20313336656.webp', 'https://www.flickr.com/photos/zaragozaantigua/20313336656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25738, 'Calle del Tenor Fleta 1951', '"Calle de Tenor Fleta. Entrada: General Mola (hoy Pв”¬в•‘ Sagasta) 23. Salida: Avenida S. Josв”ңВ® 138." Los muretes del centro indican la trinchera del ferrocarril sin cubrir. Al fondo, a la izquierda, la Capilla-Rotonda de los PP. Agustinos y su Muro perimetral. Imagen capturada desde el Paseo de Mola. Fuente visual: Archivo Pв”ңв•‘blico Municipal, Archivo Mora.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64209800, -0.88595500, '0101000020E61000002849D74CBE59ECBFDB696B4430D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20319195055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20319195055.webp', 'https://www.flickr.com/photos/zaragozaantigua/20319195055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25963, 'Casa de la Paz 1994', 'El 23 de diciembre de 1993 fue desalojada la Casa de la Paz, en el paseo de Sagasta 52. El edificio, de arquitectura eclв”ңВ®ctica, construido en 1919 y abandonado en 1961, habв”ңВЎa sido ocupado en 1987. En la imagen, de principios de 1994, miembros del colectivo de okupas de Zaragoza pintan el lema Г”ГҮВЈVenceremosГ”ГҮГҳ sobre la tapia recientemente levantada ante la casa, posteriormente derribada.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64182000, -0.88638300, '0101000020E61000002D5F97E13F5DECBF99F5622827D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52491652137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52491652137.webp', 'https://www.flickr.com/photos/zaragozaantigua/52491652137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26014, 'Vista aв”ңВ®rea Moncasi c.1990', 'Foto: Archivo Taumar (Irene Taulв”ңВ®s y Rafael Margalв”ңВ®). Vista aв”ңВ®rea del entorno comprendido entre el rв”ңВЎo Huerva (izquierda) y el paseo de Sagasta (derecha), unidos por la calle Moncasi (centro). Arriba, avenida de Goya. Abajo, calle Juan Pablo Bonet. Fuente: www.facebook.com/photo.php?fbid=1687671021456597&set=...', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.64174400, -0.88806900, '0101000020E6100000F2ECF2AD0F6BECBFBE33DAAA24D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22407906425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22407906425.webp', 'https://www.flickr.com/photos/zaragozaantigua/22407906425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21156, 'Talleres Carde y Escoriaza 1897', 'Vista exterior de los talleres de Carpinterв”ңВЎa Mecв”ңГӯnica Carde y Escoriaza, capturada desde la Subida de Cuв”ңВ®llar con el arranque del camino de las Alcachoferas a la izquierda. Fruto de la asociaciв”ңв”Ӯn del empresario francв”ңВ®s Guillermo Carde (de la firma Carde de Burdeos) con el zaragozano Nicolв”ңГӯs de Escoriaza (Talleres Escoriaza, fabricantes de carruajes para mercancв”ңВЎas y viajeros) se constituye esta empresa en 1897 que comenzв”ңв”Ӯ a construir vehв”ңВЎculos para el ferrocarril, y que pronto se especializarв”ңГӯ en material mв”ңв”Ӯvil como coches de tranvв”ңВЎas y trenes. Fuente visual: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'UNIVERSIDAD', 41.63990000, -0.88619200, '0101000020E610000035423F53AF5BECBFEE5A423EE8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19190830373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19190830373.webp', 'https://www.flickr.com/photos/zaragozaantigua/19190830373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21229, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1905', 'En 1903 se parcelв”ңв”Ӯ el "barrio de Ruiseв”ңв–’ores" en torno a la calle asв”ңВЎ denominada, a iniciativa del industrial Santiago Canti Polo, que emprendiв”ңв”Ӯ la construcciв”ңв”Ӯn de un grupo de hotelitos o viviendas unifamiliares en un terreno de su propiedad, siendo todas ellas proyectadas por el ingeniero Manuel Isasi Isasmendi. Estas viviendas eran consideradas "de recreo" por la burguesв”ңВЎa local, con la ventaja de que se hallaban "en las inmediaciones de Zaragoza". En la imagen promocional, los seis hotelitos referidos: por ejemplo, en la parte inferior, a la derecha, el denominado "Villa alta", que fue derribada en 1994. A su izquierda, el denominado "Villa Rosita", adquirido por Raimundo Balet y luego objeto de varias reformas, como la de 1919 con proyecto de Miguel в”ңГјngel Navarro Pв”ңВ®rez. Fuente visual: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial 1875-1926, IFC, 2004.', 1905, 1905, 1905, 'Anos 1900', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19017767854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19017767854.webp', 'https://www.flickr.com/photos/zaragozaantigua/19017767854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21507, 'Casa de Manuel Hernв”ңГӯndez 1923', 'Imagen capturada por Juan Mora Insa del proyecto diseв”ңв–’ado por Regino Borobio para la casa de Manuel Hernв”ңГӯndez en el Paseo de Ruiseв”ңв–’ores nв”¬в•‘ 22, esquina con un callejв”ңв”Ӯn sin nombre que en 1949 recibirв”ңГӯ el de "Fernando de Antequera". Se trataba de un edificio unifamiliar con planta sв”ңв”Ӯtano, baja y principal con aires modernistas y art dв”ңВ®co, y la plв”ңГӯstica de un espacio que se ofrece a una visual estratв”ңВ®gica entre dos calles. Estuvo en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se sumв”ңв”Ӯ el vecino nв”¬в•‘ 24) se levantв”ңв”Ӯ la actual construcciв”ңв”Ӯn. En la imagen, la casa capturada desde el Paseo de Ruiseв”ңв–’ores. A la derecha, el murete delimita el callejв”ңв”Ӯn sin nombre. A la izquierda, el enorme jardв”ңВЎn trasero que, en bajada, llegaba hasta el camino tambiв”ңВ®n arbolado por el que fluв”ңВЎa al aire la acequia de San Josв”ңВ® (futura calle Doctor Alcay). Justo detrв”ңГӯs de la casa, cruzando el callejв”ңв”Ӯn, se construirв”ңГӯ la Casa de Pedro Hernв”ңГӯndez Luna (nв”¬в•‘ 20 del paseo), obra de Regino y de Josв”ңВ® Borobio diseв”ңв–’ada en 1931. Fuente visual: "Una mirada a travв”ңВ®s de la arquitectura: Regino y Josв”ңВ® Borobio Ojeda", Daniel Estabв”ңВ®n Boldova.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15607224169.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15607224169.webp', 'https://www.flickr.com/photos/zaragozaantigua/15607224169/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21520, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1923', 'Imagen capturada por Juan Mora Insa del proyecto de Regino Borobio para la casa de Manuel Hernв”ңГӯndez en el Paseo de Ruiseв”ңв–’ores nв”¬в•‘ 22. A la derecha, esquina con un callejв”ңв”Ӯn sin nombre que en 1949 recibirв”ңГӯ el de "Fernando de Antequera". A la izquierda, el paseo de Ruiseв”ңв–’ores. Al fondo a la derecha, la nada edificatoria mв”ңГӯs absoluta hasta el camino del Sв”ңГӯbado y la acequia que por в”ңВ®l fluв”ңВЎa. Esta vivienda estuvo en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se adicionв”ңв”Ӯ el vecino nв”¬в•‘ 24, visible justo detrв”ңГӯs) se levantв”ңв”Ӯ eso que hoy puede verse. Fuente visual: "Una mirada a travв”ңВ®s de la arquitectura: Regino y Josв”ңВ® Borobio Ojeda", Daniel Estabв”ңВ®n Boldova.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16518016194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16518016194.webp', 'https://www.flickr.com/photos/zaragozaantigua/16518016194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21548, 'Tudor c.1920', 'Dibujo de la fв”ңГӯbrica de Acumuladores Tudor "La Pilar" en sus instalaciones en "Torrero" (cuando "Torrero" era considerado a partir de la actual Avenida de Goya), desde 1898 a 1945. Construida sobre la antigua harinera de Almech, la manzana del cruce del Camino de las Torres (en la parte inferior, hacia la izquierda) con la Avenida Siglo XX (que sube por la derecha hacia Torrero, con los raв”ңВЎles del tranvв”ңВЎa). En la parte superior, a la derecha, el Parque Pignatelli, y la cв”ңв•‘pula de la iglesia de S. Fernando. La fila de в”ңГӯrboles inmediatamente superior a la fв”ңГӯbrica seв”ңв–’ala la actual calle Josв”ңВ® Pellicer. Centrado en la parte superior, el barrio de los "Chiflaos" en torno a Pradilla, y la gran torre del final de Vista Alegre. El agua de la fв”ңГӯbrica era de la acequia de San Josв”ңВ® que por Ruiseв”ңв–’ores venв”ңВЎa del Canal . En 1935 la fв”ңГӯbrica sufriв”ңв”Ӯ un incendio importante, pero su utilizaciв”ңв”Ӯn como industria de guerra entre 1936-39 prolongв”ңв”Ӯ la permanencia en esta zona. Despuв”ңВ®s, una nueva ubicaciв”ңв”Ӯn, en terrenos junto a la carretera de Navarra, serв”ңГӯ realidad partir de 1946. Fuente visual: AVV. San Josв”ңВ®.', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63974900, -0.88586900, '0101000020E61000008449F1F10959ECBF0953944BE3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20315103065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20315103065.webp', 'https://www.flickr.com/photos/zaragozaantigua/20315103065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21552, 'Vista de Zaragoza c.1920', 'Vista desde el paseo de Sagasta, esquina con el Camino de las Torres. A la derecha, edificios de la fв”ңГӯbrica de acumuladores de la Tudor. Las torres de la izquierda corresponden a la yeserв”ңВЎa de Manuel Gracia, derribada en 1924 para construir Casa Faci. Al fondo, el Pilar, la Seo y otras torres de la ciudad. Fuente visual: Foto Gabriel Faci, DARA/AHPZ', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20952293484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20952293484.webp', 'https://www.flickr.com/photos/zaragozaantigua/20952293484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21624, 'P.в”¬в•‘ de Sagasta 1927', 'El zaragozano Lorenzo Gradв”ңВ® (segundo por la izquierda) posa tras su prototipo de automв”ңв”Ӯvil, aparcado frente al concesionario de la marca de vehв”ңВЎculos Oakland y Chevrolet (ambas de General Motors), regentado por Josв”ңВ® Marв”ңВЎa Orobitg en el nв”¬в•‘ 35 del paseo de Sagasta, donde la casa de Baselga (actual nв”¬в•‘ 43). Fuente: Colecciв”ңв”Ӯn particular.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64059300, -0.88618900, '0101000020E6100000F165A208A95BECBFF58590F3FED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35830718064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35830718064.webp', 'https://www.flickr.com/photos/zaragozaantigua/35830718064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21718, 'Av. de la Repв”ңв•‘blica 1934', 'Imagen de un "convoy" tranviario de la Lв”ңВЎnea 5 camino del campo de Torrero, a presenciar un emocionante partido del "Zaragoza F.C.", entidad resultante de la absorciв”ңв”Ӯn en 1932 del "Zaragoza C.D." por parte del "Iberia S.C." Los aficionados, entre ellos unos cuantos infantes equilibristas, se aferran como pueden a una atestada jardinera tirada por una unidad de la Serie 50. Hace fresco, pero con sol eso en Zaragoza no importa, por muy invierno que sea, y mв”ңГӯs si eres fanв”ңГӯtico del "sport". El convoy estв”ңГӯ subiendo por la Avenida de la Repв”ңв•‘blica, a punto de acceder a la Avenida del Siglo XX para llegar, pasado el Canal Imperial, a su destino en la Avenida de Amв”ңВ®rica, cerca del campo de "football". Hace poco que esta lв”ңВЎnea ya no pasa por el interior del Parque Pignatelli, como originalmente hacв”ңВЎa, pues a los usuarios les parecв”ңВЎa que estaba muy a desmano... En esta imagen, a la derecha hay visual, por encima del tranvв”ңВЎa, del chaflв”ңГӯn de la tardomodernista "Casa del escultor Palao", de Miguel в”ңГјngel Navarro. Al otro lado de la Avenida, a la izquierda, un pedazo de "La Pilar", la fв”ңГӯbrica de la Sociedad Espaв”ңв–’ola del Acumulador Tudor que ahв”ңВЎ estaba desde 1898. El tranvв”ңВЎa lleva una anuncio comercial de la "Fв”ңГӯbrica y Almacв”ңВ®n de Muebles Aguerri", que fuera antes de Agustв”ңВЎn Nuviala, en el Camino de San Josв”ңВ® nв”¬в•‘ 110. Fuente visual: Luis Mompel Castelar, Archivo Heraldo de Aragв”ңв”Ӯn.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19759112250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19759112250.webp', 'https://www.flickr.com/photos/zaragozaantigua/19759112250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21719, 'Incendio Tudor 1935', '"La Pilar" era la recia denominaciв”ңв”Ӯn de la fв”ңГӯbrica de la Sociedad Espaв”ңв–’ola del Acumulador Tudor que desde 1898 estaba ubicada entre el Camino de las Torres y el de las Alcachoferas. En octubre de ese aв”ңв–’o un enorme incendio arruinв”ңв”Ӯ los ingenios fabriles, a pesar del afв”ңГӯn de los obreros que colaboraron en la extinciв”ңв”Ӯn del fuego. La foto estв”ңГӯ capturada desde el arranque de la avenida del Siglo XX. Los в”ңГӯrboles del fondo indican el acceso al serpenteante camino de las Alcachoferas. Sobre el firme, raв”ңВЎles en bajada de la tranviaria lв”ңВЎnea de Torrero hacia la plaza de la Constituciв”ңв”Ӯn. Fuente visual: foto Miguel Marв”ңВЎn Chivite, para Heraldo de Aragв”ңв”Ӯn. AVV. San Josв”ңВ®.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63951700, -0.88595500, '0101000020E61000002849D74CBE59ECBF361E6CB1DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19776980524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19776980524.webp', 'https://www.flickr.com/photos/zaragozaantigua/19776980524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21742, 'Carmelitas Descalzos 1935', 'En 1929 se puso la primera piedra del nuevo Convento e Iglesia de los Carmelitas Descalzos de la ciudad, en un solar de 2133 m2 junto a la proyectada plaza de Espaв”ңв–’a y el camino de Los Cubos, en el ensanche de Miralbueno. El proyecto llevaba la firma de Secundino Zuazo, y una elevada torre destacaba de la nueva construcciв”ңв”Ӯn, pensada para una comunidad de 40 frailes. La enormidad del proyecto contaba con el beneplв”ңГӯcito polв”ңВЎtico del rв”ңВ®gimen de Primo de Rivera, y el apoyo econв”ңв”Ӯmico de suscripciones y donaciones privadas. Las obras comenzaron a buen ritmo, pero gravв”ңВЎsimos problemas con la compaв”ңв–’в”ңВЎa constructora llevaron a los promotores a suspender pagos, de forma que ya en 1933 las obras quedaron varadas. Esta es la situaciв”ңв”Ӯn que captura la imagen del conjunto de la iglesia y convento carmelita, desde la proyectada plaza de Espaв”ңв–’a. A la derecha, una de las viviendas baratas construidas en esa zona, segв”ңв•‘n proyecto de Miguel в”ңГјngel Navarro y Secundino de Zuazo, para la Sociedad Zaragozana de Urbanizaciв”ңв”Ӯn y Construcciв”ңв”Ӯn. Fuente: Foto Marв”ңВЎn Chivite, "Mundo Grв”ңГӯfico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64017400, -0.89340000, '0101000020E610000082E2C798BB96ECBFF0DFBC38F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21826660798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21826660798.webp', 'https://www.flickr.com/photos/zaragozaantigua/21826660798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21749, 'Ram de Viu 1935', 'Imagen parcial de las viviendas baratas de la Sociedad Zaragozana de Urbanizaciв”ңв”Ӯn y Construcciв”ңв”Ӯn, levantadas en 1928 junto al Huerva, en el ensanche de Miralbueno, segв”ңв•‘n proyecto de Miguel в”ңГјngel Navarro y Secundino Zuazo. En este caso, se trata de las edificadas en la manzana 48, segв”ңв•‘n proyecto de Miguel в”ңГјngel Navarro, en el arranque de la calle Ram de Viu, entre Mariano Supervв”ңВЎa, desde donde se hace la foto, y el vial luego llamado "Bruno Solano", hacia la derecha, tras la curva. Subsisten unas pocas de las originales viviendas unifamiliares. Las demв”ңГӯs han sido sustituidas por modernos bloques habitacionales. Las placas de la calle tambiв”ңВ®n son otras. Fuente: Foto Marв”ңВЎn Chivite, "Mundo Grв”ңГӯfico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63862100, -0.89451500, '0101000020E61000008E01D9EBDD9FECBFF8C43A55BED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22025743261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22025743261.webp', 'https://www.flickr.com/photos/zaragozaantigua/22025743261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21750, 'Gascв”ңв”Ӯn de Gotor 1934', 'La fenomenal invenciв”ңв”Ӯn del "Duende" de Zaragoza en 1934, por su apabullante estolidez, triunfв”ңв”Ӯ y fue extendida como encanto que propaga el viento. Pronto surgieron "primos" suyos en otras geografв”ңВЎas peninsulares, y la prensa escrita se encargв”ңв”Ӯ de apostolear detalladamente sus presuntas manifestaciones, que incluв”ңВЎan lanzamiento de piedras (Valencia), y alguna paliza gratuita (Castilla). Este de Zaragoza parecв”ңВЎa el mв”ңГӯs pacв”ңВЎfico, por eso triunfв”ңв”Ӯ, inspirв”ңв”Ӯ una falla valenciana, y se quedв”ңв”Ӯ incrustado como un referente de la Zaragoza de aquellos aв”ңв–’os, junto con el tremebundo asunto de la niв”ңв–’a Mв”¬В¬ de los Dolores Mallв”ңВ®n, que dijo haber sido raptada por "los gitanos" en el Puente del 14 de julio, y que tambiв”ңВ®n fue ampliamente cubierto por los medios de todo el paв”ңВЎs, aun despuв”ңВ®s de confesar que todo era mentira. En la imagen, encantada multitud zaragozana junto al edificio objeto de la devociв”ңв”Ӯn paranormal (a la izquierda), en la calle Gascв”ңв”Ӯn de Gotor, reunida a la espera de escuchar la quejosa "voz" de la inmaterial presencia. Al fondo, un despejado horizonte hasta la Avenida de la Repв”ңв•‘blica, con espectral vista de Casa Faci. Fuente visual: Foto Marв”ңВЎn Chivite ("Mundo Grв”ңГӯfico", Madrid).', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22026132866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22026132866.webp', 'https://www.flickr.com/photos/zaragozaantigua/22026132866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21755, 'La Dama Duende 1934', 'A finales del aв”ңв–’o 1934, muchas personas daban pв”ңГӯbulo a la existencia de un fantasma parlante ("duende") en un piso del nв”ңв•‘mero 2 de la calle de Gascв”ңв”Ӯn de Gotor. Como suceso inexplicable que era, o se creв”ңВЎa en в”ңВ®l, o no, y hubo muchos que picaron. в”¬в”җCuestiв”ңв”Ӯn de fe?, в”¬в”җmaravilla sobrenatural?, в”¬в”җsueв”ңв–’o onв”ңВЎrico?, mв”ңГӯs bien resultв”ңв”Ӯ ser una material fantasmada-broma que puso a Zaragoza en el mapa de "lo inexplicado", al tremebundo borde del descacharrante e inane cuarto milenio. Todo comenzв”ңв”Ӯ cuando la seв”ңв–’orita de la imagen, que con 16 aв”ңв–’os de edad servв”ңВЎa como doncella de un matrimonio inquilino, dijo escuchar una extraв”ңв–’a voz en la cocina: el hornillo le hablaba. Por una perfecta conjunciв”ңв”Ӯn cв”ңв”Ӯsmica, mediв”ңГӯtica, social, fenomenolв”ңв”Ӯgica, psicopatolв”ңв”Ӯgica, el lв”ңВЎo que se armв”ңв”Ӯ fue de los que marcan в”ңВ®poca, de tal forma que varias dв”ңВ®cadas despuв”ңВ®s, cuando el inmueble escenario de los hechos fue derribado, el nuevo que se construyв”ңв”Ӯ sobre su solar fue bautizado con orgullo como "Edificio Duende", y rв”ңВЎase la gente. En la imagen, la muchacha Pascuala Alcocer, oidora primera de las revelaciones del "duende" hornero, fotografiada furtivamente cuando estaba tendiendo ropa a secar en el "encantado" edificio de la calle de Gascв”ңв”Ӯn y Gotor. Al fondo, las traseras de los hotelitos pares de la Avenida de la Repв”ңв•‘blica, frente a Casa Faci. Fuente visual: Luis Garcв”ңВЎa de Linares (Semanario "Crв”ңв”Ӯnica", diciembre 1934)', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22425933961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22425933961.webp', 'https://www.flickr.com/photos/zaragozaantigua/22425933961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21851, 'Av. de la Repв”ңв•‘blica 1935', 'Imagen capturada durante el incendio que afectв”ңв”Ӯ a la nave principal de la fв”ңГӯbrica &quot;La Pilar&quot; de la Sociedad Espaв”ңв–’ola del Acumulador Tudor, sita en la avenida de la Repв”ңв•‘blica nв”¬в•‘ 87 y recayente al camino de las Alcachoferas. En primer plano, la esquina y el pretil que indica la salida de la fв”ңГӯbrica de la acequia de San Josв”ңВ® (antigua de las Adulas), y su continuaciв”ңв”Ӯn en descenso por el camino de las Torres, hacia la izquierda. Aв”ңВ®reo, el tendido elв”ңВ®ctrico de la lв”ңВЎnea 5 del tranvв”ңВЎa. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35736348184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35736348184.webp', 'https://www.flickr.com/photos/zaragozaantigua/35736348184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21924, 'Av. del Siglo XX, 1931', 'Imagen capturada en el bulevar del arranque de la avenida del Siglo XX, natural continuidad hacia el sur del paseo de Sagasta. Un tranvв”ңВЎa de la lв”ңВЎnea de Torrero asciende hacia la terminal sureв”ңв–’a. A la derecha destaca la enorme nueva casa Faci, chaflanera entre el paseo de Sagasta y el final del camino de las Torres, frente a la que se extienden almacenes e instalaciones de la Tudor. A la izquierda e inmediatas, viviendas en altura de Palau y de Abizanda.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63974100, -0.88644800, '0101000020E6100000F3583332C85DECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55061563766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55061563766.webp', 'https://www.flickr.com/photos/zaragozaantigua/55061563766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23405, 'Plataforma Logв”ңВЎstica 2005', 'Vista aв”ңВ®rea de la Plataforma Logв”ңВЎstica de Zaragoza (PLAZA), en 2005. Se trata de un polв”ңВЎgono industrial de grandes dimensiones situado junto al Canal Imperial (derecha) y la autovв”ңВЎa Zaragoza-Madrid (abajo). Se gestв”ңв”Ӯ en 2000, se comenzв”ңв”Ӯ a construir en 2002 y se inaugurв”ңв”Ӯ su primera fase en 2005. Ha protagonizado una trama de corrupciв”ңв”Ӯn por malversaciв”ңв”Ӯn de fondos entre 2004 y 2011. Fuente: www.skyscrapercity.com/', 2005, 2005, 2005, 'Siglo XXI', NULL, 41.64705900, -0.99633000, '0101000020E6100000FDC1C073EFE1EFBF8ECA4DD4D2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19298882103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19298882103.webp', 'https://www.flickr.com/photos/zaragozaantigua/19298882103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22030, 'Plaza de San Francisco 1946', 'La novв”ңВЎsima segunda unidad de la serie 200 de los tranvв”ңВЎas, realizada en Material Mв”ңв”Ӯvil y Construcciones y en servicio en la lв”ңВЎnea 11. Parque, transita por la plaza de San Francisco encaminada hacia la terminal de la plaza de Espaв”ңв–’a. Tras ella, la frondosa isleta central de la plaza que no deja ver el despejado panorama del campus universitario, y el inmueble en construcciв”ңв”Ӯn del nв”¬в•‘ 11 de la misma, esquinero con el paseo de Fernando el Catв”ңв”Ӯlico. A su lado, vaciв”ңв”Ӯ donde una dв”ңВ®cada mв”ңГӯs tarde se construirв”ңГӯ el edificio del nв”¬в•‘ 12 de la plaza. Esta unidad tranviaria, algo modificada, perdura desde hace dв”ңВ®cadas para formar parte del utв”ңв”Ӯpico Museo de Transportes de Zaragoza.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.64073500, -0.89498800, '0101000020E610000093FFC9DFBDA3ECBF8733BF9A03D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50813627796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50813627796.webp', 'https://www.flickr.com/photos/zaragozaantigua/50813627796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22137, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1954', 'Dibujo inserto en el folleto publicitario de la Residencia Femenina Universitaria Nuestra Seв”ңв–’ora del Pilar, en el paseo de Ruiseв”ңв–’ores 6-8. Estв”ңГӯ dirigida desde 1954 por las Religiosas del Apostolado del Sagrado Corazв”ңв”Ӯn de Jesв”ңв•‘s. A la derecha, la calle del Porvenir. Fuente: www.todocoleccion.net', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63792800, -0.88777900, '0101000020E61000002F6B6281AF68ECBFF299EC9FA7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24308228294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24308228294.webp', 'https://www.flickr.com/photos/zaragozaantigua/24308228294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22247, 'Cв”¬в•‘ del Sв”ңГӯbado c.1955', 'Imagen capturada en el irregular camino del Sв”ңГӯbado a la altura de la "replaceta" formada por su confluencia con la calle de la Luz (izquierda) y la calle de Gascв”ңв”Ӯn de Gotor (derecha). Al fondo de esta в”ңв•‘ltima calle destaca el alzado del nuevo colegio Calasancio construido segв”ңв•‘n proyecto del arquitecto Josв”ңВ® Luis Lafiguera, inaugurado en 1948 y con entrada principal en la calle de Sevilla. Aquв”ңВЎ presenta su aspecto antes de que fuera ampliado previo derribo del antiguo hotelito de Juan Solsona en cuyo solar se levantв”ңв”Ӯ una nueva ala recayente a la calle de Gascв”ңв”Ӯn y Gotor (antigua de la Uniв”ңв”Ӯn), ademв”ңГӯs del referencial torreв”ңв”Ӯn angular entre ambas calles. Poco despuв”ңВ®s y a partir de este punto el ascendente camino del Sв”ңГӯbado perderв”ңВЎa su secular denominaciв”ңв”Ӯn y se convertirв”ңВЎa en la calle del Arzobispo Morcillo.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63859500, -0.88909800, '0101000020E61000005B0C1EA67D73ECBFCF31207BBDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52032359764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52032359764.webp', 'https://www.flickr.com/photos/zaragozaantigua/52032359764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22342, 'Glorieta Velв”ңГӯzquez 1965', 'Imagen desde alturas de la Glorieta Diego Velв”ңГӯzquez, del final de General Mola, la entrada al Parque Pignatelli, y el comienzo de los paseos de Ruiseв”ңв–’ores y de Cuв”ңВ®llar. El chaflв”ңГӯn de la izquierda seв”ңв–’ala el final de la calle Millв”ңГӯn Astray. Por Cuв”ңВ®llar va descendiendo una unidad tranviaria compuesta de la lв”ңВЎnea 5 (Torrero-Delicias). Fuente visual: AVV. San Josв”ңВ®.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63868300, -0.88600800, '0101000020E6100000DDD1FF722D5AECBF6EC1525DC0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20213477529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20213477529.webp', 'https://www.flickr.com/photos/zaragozaantigua/20213477529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22415, 'Parque Pignatelli 1961', 'Nocturna imagen del parque de Pignatelli tras su remodelaciв”ңв”Ӯn de 1961, que le dotв”ңв”Ӯ de una de esas amables y atractivas fuentes con luces incorporadas, aunque la escasa centralidad de este parque, en la lejana periferia, y el hecho de no pasar coches alrededor, le restaba magnificencia y preciosismo. La estatua del pв”јГІocer que le dio nombre seguв”ңВЎa mirando hacia el canal, como cuando estaba en su original ubicaciв”ңв”Ӯn de la glorieta de Santa Engracia. Fuente: Ediciones Arribas, Archivo Municipal de Zaragoza. Cв”ңв”Ӯdigo de referencia: ES. 50297. AM 04.01.02.01 Sobre 01538', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25611744316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25611744316.webp', 'https://www.flickr.com/photos/zaragozaantigua/25611744316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22441, 'Vista aв”ңВ®rea San Josв”ңВ® 1960', 'Vista aв”ңВ®rea desde el barrio de San Josв”ңВ®, con el parque Pignatelli a la izquierda, junto al paseo de Cuв”ңВ®llar. A la derecha, el camino de las Alcachoferas y la futura avenida del Tenor Fleta. Fuente: TAF Helicв”ңв–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63906100, -0.88343800, '0101000020E61000009065C1C41F45ECBF149337C0CCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983157990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983157990.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983157990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22442, 'Paseo de Cuв”ңВ®llar 1960', 'Vista aв”ңВ®rea de la curva del paseo de Cuв”ңВ®llar, centrada en los bloques de la calle Luis Sallenave. A la derecha, parque de Pignatelli. Al fondo, fв”ңГӯbrica de cervezas La Zaragozana. Fuente: TAF Helicв”ңв–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63798700, -0.88414600, '0101000020E610000075745C8DEC4AECBFF722DA8EA9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983259160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983259160.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983259160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22443, 'Vista aв”ңВ®rea Cuв”ңВ®llar 1960', 'Vista aв”ңВ®rea centrada en el paseo de Cuв”ңВ®llar, con el parque de Pignatelli a la derecha, y las iglesias de San Fernando y San Antonio al fondo. Fuente: TAF Helicв”ңв–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63805100, -0.88436000, '0101000020E6100000787FBC57AD4CECBF0D17B9A7ABD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983364870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983364870.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983364870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25599, 'Agraria Vв”ңВЎa Hispanidad 1970', 'Siega de herbв”ңГӯceas en un campo de labor al oeste del Polв”ңВЎgono Gran Vв”ңВЎa, con el fondo de las calles de los Condes de Aragв”ңв”Ӯn y de Asв”ңВЎn y Palacios emergentes de bloques de viviendas. A la derecha, colegio del Sagrado Corazв”ңв”Ӯn y rosetв”ңв”Ӯn del Seminario Metropolitano Conciliar. En primer tв”ңВ®rmino, artesanal prв”ңГӯctica agrв”ңВЎcola de la cosecha de alfalfa o alfance, segado con dalla o guadaв”ңв–’a, recogido a mano, y cargado en un volquete tirado por caballerв”ңВЎa. Aunque parezca complicado viendo la imagen, estos campos darв”ңГӯn paso aв”ңв–’os despuв”ңВ®s a los bloques de la calle de Robert Baden-Powell, el Andador de Manuel Gutiв”ңВ®rrez Mellado, el Andador de Quintana Lacacci, la avenida de Juan Pablo II, y el Complejo Aragonia.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63967700, -0.91060900, '0101000020E6100000382F4E7CB523EDBF6F8099EFE0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940446495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940446495.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940446495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23680, 'Aerв”ңв”Ӯdromo Sanjurjo 1938', 'Imagen capturada en el aerв”ңв”Ӯdromo Sanjurjo de Zaragoza cuando era utilizado como base de operaciones por la alemana Legiв”ңв”Ӯn Cв”ңв”Ӯndor como franca aliada de la Espaв”ңв–’a nacionalista. En este caso la fotografв”ңВЎa ha sido realizada durante las evoluciones de varios ejemplares del bombardero ligero de la Luftwaffe "Dornier Do-17 E-1" (denominado originalmente Lв”ңГӯpiz Volador, redenominado de forma mв”ңГӯs castiza como Bacalao) allв”ңВЎ estacionados. Fuente visual: www.todocoleccion.net', 1938, 1938, 1938, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44307707041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44307707041.webp', 'https://www.flickr.com/photos/zaragozaantigua/44307707041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22456, 'Las Acacias 1960', 'Vista casi cenital de buena parte del antiguo barrio de las Acacias, vulgo "de los Chiflaos", delimitado por el paseo de Cuв”ңВ®llar (sur), las calles Vista Alegre (izquierda), Marquв”ңВ®s de Ahumada (centro), y Pradilla (derecha). Al norte, el camino de las Alcachoferas y la acequia del Entonar-Antonar, y la antigua calle del 14 de Abril, redenominada Francisco Cidв”ңв”Ӯn. A la derecha, instalaciones de la cervecera La Zaragoza, junto a la calle Ramв”ңв”Ӯn Berenguer IV (antigua de Agustв”ңВЎn Querol). El gran bloque en forma de "V" invertida es el motivo de la fotografв”ңВЎa, ubicado en una antigua zona de baldв”ңВЎo en la que recaв”ңВЎan los huertos de los hotelitos preexistentes, e ilustra muy bien la estudiada integraciв”ңв”Ӯn entre lo que habв”ңВЎa antes, y lo moderno. Es importante porque marca tendencia sobre la mutaciв”ңв”Ӯn que sucederв”ңГӯ, a partir de entonces, en su entorno, salvo alguna contada excepciв”ңв”Ӯn. Aunque parezca increв”ңВЎble, en el triangular espacio dejado por el nuevo bloque hasta el paseo de Cuв”ңВ®llar, aв”ңв–’os despuв”ңВ®s crecerв”ңВЎa un bloque mв”ңГӯs moderno aв”ңв•‘n, en escala, y en integraciв”ңв”Ӯn zonal. La futura calle Luis Sallenave, el vial resultante entre ambos bloques, que tiene sendas preciosas placas cerв”ңГӯmicas en su entrada y salida, es una de las calles de Zaragoza mв”ңГӯs amargamente indescriptibles. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63795500, -0.88372200, '0101000020E6100000CB2E185C7347ECBFEBA86A82A8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31645073671.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31645073671.webp', 'https://www.flickr.com/photos/zaragozaantigua/31645073671/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22486, 'Calle de Supervв”ңВЎa 1966', 'Imagen capturada en la cancha de balonmano situada en las traseras del Hogar "Sierra de Alcubierre", promovido en 1942 por el Auxilio Social de Falange Espaв”ңв–’ola para recoger hasta 160 huв”ңВ®rfanos de la "Revoluciв”ңв”Ӯn y la Guerra", con diseв”ңв–’o del arquitecto Josв”ңВ® Beltrв”ңГӯn Navarro. El ingreso principal estaba localizado en la moderna calle de Mariano Supervв”ңВЎa 27-29 (a la izquierda, fuera de plano), dentro del conjunto de las Casas Baratas de Miralbueno, junto al rв”ңВЎo Huerva. Al fondo, despejado e insв”ңв”Ӯlito panorama hasta los bloques impares del principio de la calle de Cosme Blasco y el gran Colegio Mayor de La Salle. A la izquierda, casitas de la calle de Francisco de La Ripa. Inopв”ңВјnadamente y a la derecha emerge la chimenea de la antigua fв”ңГӯbrica textil de Cв”ңГӯndido Castillo, en una zona despuв”ңВ®s edificada con modernos bloques de vivienda. Fuente visual: Gerardo Sancho Ramo, AMZ', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63864500, -0.89272300, '0101000020E61000005F622CD32F91ECBF80608E1EBFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40477693072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40477693072.webp', 'https://www.flickr.com/photos/zaragozaantigua/40477693072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22493, 'Calle de Sevilla 1966', 'Imagen capturada en la chaflanera esquina entre la calle de Gascв”ңв”Ӯn de Gotor y la de Sevilla, y centrada en el los bajos comerciales del moderno inmueble del nв”¬в•‘ 17 de esa в”ңв•‘ltima calle, donde estaba radicado el establecimiento Marcal, especializado en molduras y marcos, asв”ңВЎ como los papeles pintados, que en esa dв”ңВ®cada y sobre todo en la siguiente protagonizaron de forma explosiva, para bien y para mal, la decoraciв”ңв”Ӯn de las paredes en muchos hogares del paв”ңВЎs. Hacia la izquierda, vista parcial de algunas de las parcelas que subsistв”ңВЎan en el lado de los impares del tramo de la calle de Sevilla desde su arranque en el cruce con la calle del Doctor Alcay. Pocos aв”ңв–’os despuв”ңВ®s comenzaron a ser derribadas y sustituidas por modernos inmuebles. En primer tв”ңВ®rmino, trasera de un Renault Gordini. A la derecha, Comercial Parв”ңВЎs, que persevera hoy en dв”ңВЎa en sus veteranas funciones de ferreterв”ңВЎa y droguerв”ңВЎa.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63904400, -0.88793900, '0101000020E610000066F9BA0CFF69ECBF3E5A9C31CCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48120931677.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48120931677.webp', 'https://www.flickr.com/photos/zaragozaantigua/48120931677/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22558, 'Plaza San Francisco c.1970', 'Postal. Tranvв”ңВЎa. Monumento a Fernando el Catв”ңв”Ӯlico. Fuente: www.facebook.com/photo.php?fbid=1567234190171478&set=...', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15207188111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15207188111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15207188111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22590, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1977', 'Imagen del paseo de Ruiseв”ңв–’ores en la acera de los pares, en el tramo en torno a la calle Fernando de Antequera. A la derecha, aspecto parcial del nв”¬в•‘ 10, transformado en 2002; el representativo bloque de los nв”ңв•‘meros 14-16, muestra de la arquitectura de autor de finales de los 60, proyectado por Enrique Delso Calavia; el nв”¬в•‘ 18, superviviente en precario desde mediados del siglo pasado, aunque abandonado y pendiente de piqueta; el nв”¬в•‘ 20, la antigua casa de Pedro Hernв”ңГӯndez Luna (diseв”ңв–’o racionalista de los Borobia), reconvertida y transformada en los aв”ңв–’os 40-50 en la actual Clв”ңВЎnica del Pilar; y aspecto del nв”¬в•‘ 22, la casa de Manuel Hernв”ңГӯndez, en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se sumв”ңв”Ӯ su vecino nв”¬в•‘ 24 de la izquierda) se levantв”ңв”Ӯ la actual construcciв”ңв”Ӯn. Fuente visual: "La evoluciв”ңв”Ӯn urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15756223795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15756223795.webp', 'https://www.flickr.com/photos/zaragozaantigua/15756223795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22597, 'P.в”¬в•‘ de Ruiseв”ңв–’ores 1974', 'Luminoso paseo de los Ruiseв”ңв–’ores con visual, a la izquierda, de los pares, en el tramo en torno a la calle Fernando de Antequera y Santiago Guallar, con aspecto del bloque de los nв”ңв•‘meros 14-16, proyectado por Enrique Delso Calavia, cuando aв”ңв•‘n tenв”ңВЎa peces en su particular estanque; del nв”¬в•‘ 18, superviviente en precario desde mediados del siglo pasado, aunque abandonado y pendiente de piqueta; y el nв”¬в•‘ 20, la antigua casa de Pedro Hernв”ңГӯndez Luna, transformada en los aв”ңв–’os 40-50 en la actual Clв”ңВЎnica del Pilar. En la acera de los impares, a la derecha, una despejada e irrepetible vista de la antigua "Casa del Poeta" Alberto Casaв”ңв–’al Shackery, construida en 1930 por suscripciв”ңв”Ӯn popular, y que serв”ңГӯ piqueteada por sus herederos en 2004 para mejor aprovechar el espacio. Un poco antes, aspecto de los antiguos muros perimetrales del nв”¬в•‘ 31-33, antes de no poder resistir el empuje de una otra piqueta. Fuente visual: www.facebook.com/photo.php?fbid=1567316920163205&set=...', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18040624868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18040624868.webp', 'https://www.flickr.com/photos/zaragozaantigua/18040624868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25601, 'Feria de Muestras 1975', 'Feria de Muestras 1975. Vista aв”ңВ®rea de la Feria de Muestras celebrada ese aв”ңв–’o durante el mes de octubre.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084724301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084724301.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084724301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25604, 'La Romareda 1957', '"Estadio de La Romareda". Imagen del Estadio Municipal de La Romareda, el aв”ңв–’o de su inauguraciв”ңв”Ӯn oficial. Captura realizada desde la inmediata "Residencia Sanitaria Josв”ңВ® Antonio". Fuente: Cв”ңВ®sar Gracia Jarque. 1957.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63637700, -0.90139300, '0101000020E61000008BFCFA2136D8ECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15750753798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15750753798.webp', 'https://www.flickr.com/photos/zaragozaantigua/15750753798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
